--

CREATE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.profiles (id, email, phone, role)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.phone,
    'user'::public.user_role
  );
  RETURN NEW;
END;
$$;


--
-- Name: set_resolved_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."set_resolved_at"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  -- Set resolved_at when status transitions to RESOLVED
  IF NEW.status = 'RESOLVED' AND (OLD.status IS DISTINCT FROM 'RESOLVED') THEN
    NEW.resolved_at := COALESCE(NEW.resolved_at, now());
  END IF;
  -- Clear resolved_at if incident is re-opened
  IF NEW.status IN ('OPEN', 'INVESTIGATING') AND OLD.status = 'RESOLVED' THEN
    NEW.resolved_at := NULL;
  END IF;
  RETURN NEW;
END;
$$;


